```class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        vector<int> hcf(n, 1);
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (__gcd(nums[i], nums[j]) > 1) {
                    hcf[i] = __gcd(hcf[i], __gcd(nums[i], nums[j]));
                }
            }
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (hcf[i] >= 2) {
                res = max(res, i + 1);
            }
        }
        for (int i = 0; i < maxC; i++) {
            int idx = -1;
            int maxHcf = 0;
            for (int j = 0; j < n; j++) {
                if (hcf[j] > maxHcf) {
                    maxHcf = hcf[j];
                    idx = j;
                }
            }
            if (idx != -1) {
                hcf[idx] = 1;
                res = max(res, idx + 1);
            }
        }
        return res;
    }
};
